# 输入获取
m = int(input())
arrM = list(map(int, input().split()))

n = int(input())
arrN = list(map(int, input().split()))


# 算法入口
def getResult(arrM, arrN):
    setM = set(arrM)
    setN = set(arrN)

    countM = {}
    for m in arrM:
        if m in setN:
            if countM.get(m) is None:
                countM[m] = 1
            else:
                countM[m] += 1

    countN = {}
    for n in arrN:
        if n in setM:
            if countN.get(n) is None:
                countN[n] = 1
            else:
                countN[n] += 1

    count = 0
    for k in countM.keys():
        count += countM[k] * countN[k]

    return count


# 算法调用
print(getResult(arrM, arrN))
